module top_module(gclk,clk,enable,scan_enable);output gclk; 
 input clk; 
 input enable; 
 input scan_enable; 
 wire obf_enable_in = (enable | scan_enable); 
 reg enable_latch; 
 always @(clk or obf_enable_in) 
  if (~clk) 
  enable_latch <= obf_enable_in; 
 assign gclk = (clk & enable_latch); 
 endmodule
